import React from 'react';
import EyePanel from './components/EyePanel';
import './App.css';

export default function App() {
  return (
    <div className="app">
      <section className="panel panel-eye">
        <EyePanel />
      </section>

      <section className="panel panel-text">
        <div className="brand">
          <h1 className="brand-line line-1">RU</h1>
          <h1 className="brand-line line-2">SHAKTI</h1>
          <p className="tagline">Empowering Strength &bull; Inspiring Grace</p>
        </div>
      </section>
    </div>
  );
}
